import Blog1 from "../assets/blogs/blog1.png";
import Blog2 from "../assets/blogs/blog2.png";
import Blog3 from "../assets/blogs/blog3.png";

export interface Blog {
  id: number;
  image: string;
  category: string;
  title: string;
  description: string;
  content: string[];
  author: string;
  date: string;
  readTime: string;
}

export const blogData: Blog[] = [
  {
    id: 1,
    image: Blog1,
    category: "resources",
    title: "Top Resources for Business Management",
    description:
      "Sit egestas vitae dignissim adipiscing. Eget volutpat pharetra sollio velit egestas nulla.",
    content: [
      "In today's competitive business landscape, having access to the right resources can make all the difference. Our comprehensive guide covers the top tools and platforms that can streamline your business operations.",
      "From project management solutions like Asana and Trello to advanced analytics platforms like Tableau, we've tested and reviewed dozens of options to bring you the most effective resources.",
      "One often overlooked resource is mentorship programs. Connecting with experienced business leaders can provide insights no software can match. We include recommendations for finding quality mentorship opportunities.",
      "Finally, we discuss how to integrate these resources effectively. It's not just about having the tools, but using them in a way that complements your unique business processes and team dynamics.",
    ],
    author: "Jane Smith",
    date: "May 15, 2023",
    readTime: "8 min read",
  },
  {
    id: 2,
    image: Blog2,
    category: "guides",
    title: "Your Roadmap to Success",
    description:
      "Cras turpis diam at suscipit nunc sit tempus in. Libero facilisis in volutpat euismod tincidunt orci.",
    content: [
      "Success doesn't happen by accident. Our step-by-step roadmap breaks down the journey into manageable phases, each with clear milestones and actionable steps.",
      "Phase 1 focuses on foundation building. Many businesses rush through this critical stage, but we emphasize the importance of solid groundwork before scaling.",
      "The intermediate phases cover strategic growth tactics, including market expansion strategies and team building exercises that foster innovation.",
      "Our final phase addresses sustainability. True success isn't just about reaching the top, but maintaining your position through continuous improvement and adaptation.",
    ],
    author: "Michael Johnson",
    date: "June 2, 2023",
    readTime: "10 min read",
  },
  {
    id: 3,
    image: Blog3,
    category: "updates",
    title: "Latest Updates in ERP Technology",
    description:
      "Rhoncus tincidunt augue tincidunt nulla faucibus morbi faucibus libero. Massa sit commodo.",
    content: [
      "The ERP landscape has undergone significant changes in the past year. We break down the most impactful updates from leading providers like SAP, Oracle, and Microsoft Dynamics.",
      "One major trend is the integration of AI capabilities directly into ERP systems. These aren't just superficial additions - they're fundamentally changing how businesses forecast and plan.",
      "We also examine the shift toward modular ERP solutions that allow businesses to pay only for the features they need, with the flexibility to scale as requirements change.",
      "Security updates are another critical area. With increasing cyber threats, modern ERP systems are incorporating advanced protection mechanisms that go beyond traditional firewalls.",
    ],
    author: "Sarah Williams",
    date: "June 18, 2023",
    readTime: "12 min read",
  },
];

export const getBlogsByCategory = (category = "all") => {
  return category === "all"
    ? blogData
    : blogData.filter((blog) => blog.category === category);
};
